@app.get("/v1/models")
def list_models(request: Request):
    _require_auth(request)
    tenant_id = _require_tenant(request)
    with _index_lock:
        idx = _load_index(tenant_id)
    models = list(idx.get("models", {}).values())
    return {"tenant_id": tenant_id, "count": len(models), "models": models}


@app.post("/v1/models/upload")
async def upload_model(
    request: Request,
    file: UploadFile = File(...),
    name: Optional[str] = Form(None),
    notes: Optional[str] = Form(None),
):
    _require_auth(request)
    tenant_id = _require_tenant(request)

    content = await file.read()
    _enforce_upload_limits(content)

    model_id = uuid.uuid4().hex
    filename = _safe_filename(file.filename or "model.pkl")
    path = _model_file_path(tenant_id, model_id, filename)

    sha = _sha256_bytes(content)
    try:
        with open(path, "wb") as f:
            f.write(content)
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Failed to store model: {type(e).__name__}: {e}")

    rec = {
        "model_id": model_id,
        "name": name or filename,
        "filename": filename,
        "size_bytes": len(content),
        "sha256": sha,
        "created_at": _now(),
        "content_type": file.content_type,
        "notes": notes,
        "path": path,
    }

    with _index_lock:
        idx = _load_index(tenant_id)
        idx.setdefault("models", {})[model_id] = rec
        _save_index(tenant_id, idx)

    return {"tenant_id": tenant_id, "model": rec, "hint": "Set ALLOW_PICKLE=true to enable loading via pickle.load"}


@app.get("/v1/models/{model_id}")
def get_model(request: Request, model_id: str):
    _require_auth(request)
    tenant_id = _require_tenant(request)
    rec = _get_model_record(tenant_id, model_id)
    safe = dict(rec)
    safe.pop("path", None)
    return {"tenant_id": tenant_id, "model": safe}


@app.delete("/v1/models/{model_id}")
def delete_model(request: Request, model_id: str):
    _require_auth(request)
    tenant_id = _require_tenant(request)

    with _index_lock:
        idx = _load_index(tenant_id)
        rec = idx.get("models", {}).get(model_id)
        if not rec:
            raise HTTPException(status_code=404, detail="Model not found")
        path = rec.get("path")
        idx["models"].pop(model_id, None)
        _save_index(tenant_id, idx)

    _cache_drop(tenant_id, model_id)
    if path and os.path.exists(path):
        try:
            os.remove(path)
        except Exception:
            pass

    return {"tenant_id": tenant_id, "deleted": model_id}


@app.post("/v1/models/{model_id}/predict")
def predict(request: Request, model_id: str, payload: PredictRequest):
    _require_auth(request)
    tenant_id = _require_tenant(request)

    model = _cache_get(tenant_id, model_id)
    if model is None:
        model = _load_model_from_disk(tenant_id, model_id)
        _cache_set(tenant_id, model_id, model)

    try:
        y = _infer(model, payload)
        try:
            json.dumps(y)
            out = y
        except Exception:
            out = {"__non_json_serializable__": True, "repr": repr(y)}
        return {"tenant_id": tenant_id, "model_id": model_id, "outputs": out}
    except HTTPException:
        raise
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Inference failed: {type(e).__name__}: {e}")


